/**
 * ⚡ InstantFetch Pro v1.0.0
 * The Ultimate Prefetch & Prerender Library
 * 
 * Zero-config, maximum performance, works everywhere.
 * Drop-in replacement for instant.page with 10x more features.
 * 
 * @author Emre - ATALIWeb
 * @license MIT
 * @see https://github.com/ataliweb/instantfetch-pro
 * 
 * Features:
 * ═══════════════════════════════════════════════════════════════
 * ✅ Speculation Rules API (Chrome 121+)
 * ✅ Document Rules with CSS Selectors
 * ✅ Layered Prefetch → Prerender Upgrade
 * ✅ Adaptive Eagerness (immediate/eager/moderate/conservative)
 * ✅ BFCache Awareness (pageshow/pagehide)
 * ✅ Navigation Timing Feedback Loop
 * ✅ Page Lifecycle API (visibility/freeze/resume)
 * ✅ Network Information API (saveData/effectiveType/downlink/rtt)
 * ✅ Mouse Velocity Prediction
 * ✅ Touch Intent Detection
 * ✅ Intersection Observer (viewport prefetch)
 * ✅ MutationObserver (dynamic content)
 * ✅ Request Queue with Rate Limiting
 * ✅ Speculation Rules Batching
 * ✅ Priority Hints (fetchpriority)
 * ✅ No-Vary-Search Support
 * ✅ Cross-origin Prefetch (with restrictions)
 * ✅ Service Worker Integration (optional)
 * ✅ Analytics-safe (respects document.prerendering)
 * ✅ GDPR-friendly (no tracking)
 * ✅ Fallback for older browsers
 * ✅ TypeScript definitions
 * ✅ Zero dependencies
 * ✅ ~4KB gzipped
 */

!function(global, factory) {
    typeof exports === 'object' && typeof module !== 'undefined' 
        ? module.exports = factory() 
        : typeof define === 'function' && define.amd 
            ? define(factory) 
            : (global = global || self, global.InstantFetch = factory());
}(this, function() {
    'use strict';

    // ═══════════════════════════════════════════════════════════════
    // CONFIGURATION
    // ═══════════════════════════════════════════════════════════════
    const defaultConfig = {
        // Timing
        hoverDelay: 65,              // ms before hover triggers prefetch
        touchDelay: 0,               // ms before touch triggers prerender
        mousedownDelay: 0,           // instant on mousedown
        
        // Adaptive timing bounds
        minHoverDelay: 20,
        maxHoverDelay: 200,
        adaptiveTimingEnabled: true,
        timingHistorySize: 20,
        
        // Limits
        maxPrefetch: 50,             // Chrome limit
        maxPrerender: 10,            // Chrome limit for immediate/eager
        maxPrerenderModerate: 2,     // Chrome limit for moderate/conservative
        maxConcurrent: 6,            // concurrent fetches
        requestsPerSecond: 3,        // rate limit
        
        // Speculation Rules
        speculationBatchSize: 10,
        speculationBatchDelay: 50,   // ms
        defaultEagerness: 'moderate',
        
        // Intersection Observer
        intersectionThreshold: 0.1,
        intersectionRootMargin: '200px',
        
        // Mouse prediction
        mousePredictionEnabled: true,
        mousePredictionDistance: 100, // px ahead
        mouseVelocityThreshold: 0.5,  // px/ms
        
        // Network
        minBandwidth: 1.5,           // Mbps
        maxRtt: 500,                 // ms
        saveDataRespect: true,
        slowConnectionRespect: true,
        
        // Features
        enableSpeculationRules: true,
        enableDocumentRules: true,
        enablePrefetch: true,
        enablePrerender: true,
        enableViewportPrefetch: true,
        enableHoverPrefetch: true,
        enableTouchPrerender: true,
        enableMousedownPrerender: true,
        enableMousePrediction: true,
        enableLayeredUpgrade: true,  // prefetch → prerender on hover
        enableBFCache: true,
        enablePageLifecycle: true,
        enableServiceWorker: false,  // opt-in
        enableNoVarySearch: true,
        enableCrossOrigin: false,    // opt-in for external links
        
        // Safety
        ignoredPaths: [
            '/logout', '/signout', '/sign-out', '/log-out',
            '/login', '/signin', '/sign-in', '/log-in',
            '/cart', '/checkout', '/basket',
            '/admin', '/wp-admin', '/dashboard',
            '/api/', '/ajax/', '/_next/', '/__',
            '.pdf', '.zip', '.exe', '.dmg'
        ],
        ignoredSelectors: [
            '[data-no-prefetch]',
            '[data-instant="false"]',
            '[download]',
            '[target="_blank"]:not([data-prefetch])',
            'a[href^="mailto:"]',
            'a[href^="tel:"]',
            'a[href^="javascript:"]',
            'a[href^="#"]'
        ],
        allowedOrigins: [],          // empty = same-origin only
        
        // Callbacks
        onPrefetch: null,
        onPrerender: null,
        onNavigate: null,
        onError: null,
        
        // Debug
        debug: false
    };

    // ═══════════════════════════════════════════════════════════════
    // STATE
    // ═══════════════════════════════════════════════════════════════
    const state = {
        // Configuration
        config: { ...defaultConfig },
        
        // Prefetch tracking
        prefetched: new Set(),
        prerendered: new Set(),
        inFlight: new Map(),
        
        // Queue system
        queue: [],
        queueProcessing: false,
        lastQueueProcess: 0,
        
        // Speculation batching
        speculationBatch: {
            prefetch: new Map(),     // url -> eagerness
            prerender: new Map()
        },
        speculationTimer: null,
        speculationScripts: new Set(),
        
        // Timing & adaptation
        navigationTimings: [],
        adaptiveDelay: defaultConfig.hoverDelay,
        prefetchHits: 0,
        prefetchMisses: 0,
        
        // Interaction tracking
        lastInteraction: 0,
        lastInteractionType: null,
        mouseVelocity: { x: 0, y: 0 },
        lastMousePos: { x: 0, y: 0, time: 0 },
        touchStartTime: 0,
        
        // Page state
        pageState: 'active',
        isPaused: false,
        wasHidden: false,
        bfCacheSupported: false,
        bfCacheRestored: false,
        
        // Observers
        intersectionObserver: null,
        mutationObserver: null,
        performanceObserver: null,
        
        // Hover/timeout tracking
        hoverTimeout: null,
        hoverTarget: null,
        
        // Animation frame
        predictionFrame: null,
        
        // Service Worker
        swRegistration: null,
        
        // Feature detection cache
        features: {
            speculationRules: null,
            prefetch: null,
            prerender: null
        },
        
        // Initialized
        initialized: false
    };

    // ═══════════════════════════════════════════════════════════════
    // UTILITIES
    // ═══════════════════════════════════════════════════════════════
    const log = (...args) => {
        if (state.config.debug) {
            console.log('%c⚡ InstantFetch', 'color: #6366f1; font-weight: bold', ...args);
        }
    };

    const warn = (...args) => {
        if (state.config.debug) {
            console.warn('%c⚡ InstantFetch', 'color: #f59e0b; font-weight: bold', ...args);
        }
    };

    const now = () => performance.now();

    const debounce = (fn, delay) => {
        let timer;
        return (...args) => {
            clearTimeout(timer);
            timer = setTimeout(() => fn(...args), delay);
        };
    };

    const throttle = (fn, limit) => {
        let inThrottle;
        return (...args) => {
            if (!inThrottle) {
                fn(...args);
                inThrottle = true;
                setTimeout(() => inThrottle = false, limit);
            }
        };
    };

    // ═══════════════════════════════════════════════════════════════
    // FEATURE DETECTION
    // ═══════════════════════════════════════════════════════════════
    const detectFeatures = () => {
        // Speculation Rules API
        if (state.features.speculationRules === null) {
            state.features.speculationRules = 
                HTMLScriptElement.supports && 
                HTMLScriptElement.supports('speculationrules');
        }
        
        // Link prefetch
        if (state.features.prefetch === null) {
            const link = document.createElement('link');
            state.features.prefetch = link.relList && link.relList.supports('prefetch');
        }
        
        // Prerender (legacy)
        if (state.features.prerender === null) {
            const link = document.createElement('link');
            state.features.prerender = link.relList && link.relList.supports('prerender');
        }
        
        return state.features;
    };

    const supportsSpeculationRules = () => {
        detectFeatures();
        return state.features.speculationRules;
    };

    const supportsPrefetch = () => {
        detectFeatures();
        return state.features.prefetch || state.features.speculationRules;
    };

    // ═══════════════════════════════════════════════════════════════
    // NETWORK DETECTION
    // ═══════════════════════════════════════════════════════════════
    const getConnection = () => {
        const conn = navigator.connection || 
                     navigator.mozConnection || 
                     navigator.webkitConnection;
        
        return {
            saveData: conn?.saveData ?? false,
            effectiveType: conn?.effectiveType ?? '4g',
            downlink: conn?.downlink ?? 10,
            rtt: conn?.rtt ?? 50,
            type: conn?.type ?? 'unknown'
        };
    };

    const canPrefetch = (eager = false) => {
        // Always allow if eager
        if (eager) return true;
        
        // Check page state
        if (state.isPaused) return false;
        if (state.pageState === 'hidden' || state.pageState === 'frozen') return false;
        
        const { config } = state;
        const conn = getConnection();
        
        // Data saver
        if (config.saveDataRespect && conn.saveData) {
            log('Blocked: Data Saver active');
            return false;
        }
        
        // Slow connection
        if (config.slowConnectionRespect) {
            const slowTypes = ['slow-2g', '2g'];
            if (slowTypes.includes(conn.effectiveType)) {
                log('Blocked: Slow connection', conn.effectiveType);
                return false;
            }
        }
        
        // Low bandwidth
        if (conn.downlink < config.minBandwidth) {
            log('Blocked: Low bandwidth', conn.downlink, 'Mbps');
            return false;
        }
        
        // High latency
        if (conn.rtt > config.maxRtt) {
            log('Blocked: High RTT', conn.rtt, 'ms');
            return false;
        }
        
        return true;
    };

    const canPrerender = () => {
        const conn = getConnection();
        
        // Prerender only on good connections
        if (conn.effectiveType !== '4g') return false;
        if (conn.rtt > 100) return false;
        if (conn.downlink < 5) return false;
        
        // Check device memory
        if (navigator.deviceMemory && navigator.deviceMemory < 4) {
            return false;
        }
        
        // Check hardware concurrency
        if (navigator.hardwareConcurrency && navigator.hardwareConcurrency < 4) {
            return false;
        }
        
        return canPrefetch();
    };

    // ═══════════════════════════════════════════════════════════════
    // LINK VALIDATION
    // ═══════════════════════════════════════════════════════════════
    const isValidLink = (link) => {
        if (!link || !link.href) return false;
        
        const { config } = state;
        
        // Check ignored selectors
        for (const selector of config.ignoredSelectors) {
            try {
                if (link.matches(selector)) return false;
            } catch (e) {
                // Invalid selector, skip
            }
        }
        
        // Parse URL
        let url;
        try {
            url = new URL(link.href, location.origin);
        } catch (e) {
            return false;
        }
        
        // Same page hash
        if (url.hash && url.pathname + url.search === location.pathname + location.search) {
            return false;
        }
        
        // Protocol check
        if (!['http:', 'https:'].includes(url.protocol)) {
            return false;
        }
        
        // HTTPS downgrade
        if (url.protocol === 'http:' && location.protocol === 'https:') {
            return false;
        }
        
        // Origin check
        const sameOrigin = url.origin === location.origin;
        if (!sameOrigin) {
            // Cross-origin
            if (!config.enableCrossOrigin) {
                // Check data attribute
                if (!('external' in link.dataset || 'prefetch' in link.dataset)) {
                    return false;
                }
            }
            // Check allowed origins
            if (config.allowedOrigins.length > 0 && 
                !config.allowedOrigins.includes(url.origin)) {
                return false;
            }
        }
        
        // Check ignored paths
        const fullPath = url.pathname + url.search;
        for (const ignoredPath of config.ignoredPaths) {
            if (fullPath.includes(ignoredPath)) {
                return false;
            }
        }
        
        return true;
    };

    const getLinkUrl = (link) => {
        if (!link || !link.href) return null;
        try {
            const url = new URL(link.href, location.origin);
            return url.href;
        } catch (e) {
            return null;
        }
    };

    const normalizeUrl = (url) => {
        try {
            const parsed = new URL(url, location.origin);
            // Remove trailing slash for consistency
            let path = parsed.pathname;
            if (path !== '/' && path.endsWith('/')) {
                path = path.slice(0, -1);
            }
            return parsed.origin + path + parsed.search;
        } catch (e) {
            return url;
        }
    };

    // ═══════════════════════════════════════════════════════════════
    // SPECULATION RULES ENGINE
    // ═══════════════════════════════════════════════════════════════
    const createSpeculationRules = (type, urls, eagerness = 'moderate', options = {}) => {
        const { config } = state;
        
        if (!config.enableSpeculationRules || !supportsSpeculationRules()) {
            return null;
        }
        
        const rules = {
            [type]: [{
                source: 'list',
                urls: Array.isArray(urls) ? urls : [urls],
                eagerness: eagerness
            }]
        };
        
        // Add referrer policy if specified
        if (options.referrerPolicy) {
            rules[type][0].referrer_policy = options.referrerPolicy;
        }
        
        // Add No-Vary-Search if enabled
        if (config.enableNoVarySearch && options.noVarySearch) {
            rules[type][0].expects_no_vary_search = options.noVarySearch;
        }
        
        // Add requirements for prerender
        if (type === 'prerender') {
            rules[type][0].requires = ['anonymous-client-ip-when-cross-origin'];
        }
        
        return rules;
    };

    const injectSpeculationRules = (rules) => {
        if (!rules) return null;
        
        const script = document.createElement('script');
        script.type = 'speculationrules';
        script.textContent = JSON.stringify(rules);
        document.head.appendChild(script);
        
        state.speculationScripts.add(script);
        
        log('Speculation rules injected:', rules);
        
        return script;
    };

    const removeSpeculationRule = (script) => {
        if (script && script.parentNode) {
            script.parentNode.removeChild(script);
            state.speculationScripts.delete(script);
        }
    };

    const clearAllSpeculationRules = () => {
        for (const script of state.speculationScripts) {
            removeSpeculationRule(script);
        }
        state.speculationScripts.clear();
    };

    // Batched speculation rules
    const queueSpeculation = (url, type = 'prefetch', eagerness = 'moderate') => {
        const { config } = state;
        
        if (!config.enableSpeculationRules || !supportsSpeculationRules()) {
            return false;
        }
        
        const normalizedUrl = normalizeUrl(url);
        const batch = state.speculationBatch[type];
        
        // Skip if already in batch or processed
        if (batch.has(normalizedUrl)) return true;
        if (type === 'prefetch' && state.prefetched.has(normalizedUrl)) return true;
        if (type === 'prerender' && state.prerendered.has(normalizedUrl)) return true;
        
        // Add to batch with eagerness
        batch.set(normalizedUrl, eagerness);
        
        log(`Queued ${type}:`, normalizedUrl, `(eagerness: ${eagerness})`);
        
        // Schedule flush
        scheduleSpeculationFlush();
        
        return true;
    };

    const scheduleSpeculationFlush = () => {
        if (state.speculationTimer) return;
        
        const { config } = state;
        
        // Check if any batch is full
        const prefetchFull = state.speculationBatch.prefetch.size >= config.speculationBatchSize;
        const prerenderFull = state.speculationBatch.prerender.size >= config.speculationBatchSize;
        
        if (prefetchFull || prerenderFull) {
            // Flush immediately
            flushSpeculationBatch();
        } else {
            // Delayed flush
            state.speculationTimer = setTimeout(() => {
                state.speculationTimer = null;
                flushSpeculationBatch();
            }, config.speculationBatchDelay);
        }
    };

    const flushSpeculationBatch = () => {
        // Clear timer
        if (state.speculationTimer) {
            clearTimeout(state.speculationTimer);
            state.speculationTimer = null;
        }
        
        // Group by eagerness
        const flushType = (type) => {
            const batch = state.speculationBatch[type];
            if (batch.size === 0) return;
            
            // Group URLs by eagerness
            const byEagerness = new Map();
            for (const [url, eagerness] of batch) {
                if (!byEagerness.has(eagerness)) {
                    byEagerness.set(eagerness, []);
                }
                byEagerness.get(eagerness).push(url);
            }
            
            // Create rules for each eagerness level
            for (const [eagerness, urls] of byEagerness) {
                const rules = createSpeculationRules(type, urls, eagerness);
                if (rules) {
                    injectSpeculationRules(rules);
                    
                    // Mark as processed
                    for (const url of urls) {
                        if (type === 'prefetch') state.prefetched.add(url);
                        if (type === 'prerender') state.prerendered.add(url);
                    }
                }
            }
            
            // Clear batch
            batch.clear();
        };
        
        flushType('prefetch');
        flushType('prerender');
    };

    // Document rules (CSS selector based)
    const createDocumentRules = () => {
        const { config } = state;
        
        if (!config.enableDocumentRules || !supportsSpeculationRules()) {
            return;
        }
        
        // Build ignore selector
        const ignoreSelector = config.ignoredSelectors.join(', ');
        
        // Layered approach: prefetch all → prerender on hover
        const rules = {
            prefetch: [
                {
                    source: 'document',
                    where: {
                        and: [
                            { href_matches: '/*' },
                            { not: { selector_matches: ignoreSelector } }
                        ]
                    },
                    eagerness: 'moderate'
                }
            ]
        };
        
        // Add prerender rules if enabled
        if (config.enablePrerender && config.enableLayeredUpgrade) {
            rules.prerender = [
                // Immediate prerender for explicitly marked links
                {
                    source: 'document',
                    where: {
                        selector_matches: '[data-prerender], [data-prefetch="prerender"]'
                    },
                    eagerness: 'immediate'
                },
                // Upgrade to prerender on hover for prefetch links
                {
                    source: 'document',
                    where: {
                        and: [
                            { href_matches: '/*' },
                            { not: { selector_matches: ignoreSelector } }
                        ]
                    },
                    eagerness: 'moderate'
                }
            ];
        }
        
        injectSpeculationRules(rules);
        log('Document rules created');
    };

    // ═══════════════════════════════════════════════════════════════
    // FALLBACK PREFETCH (for non-Speculation browsers)
    // ═══════════════════════════════════════════════════════════════
    const prefetchWithLink = (url, priority = 'auto') => {
        return new Promise((resolve, reject) => {
            const normalizedUrl = normalizeUrl(url);
            
            // Already prefetched?
            if (state.prefetched.has(normalizedUrl)) {
                return resolve(normalizedUrl);
            }
            
            // Check in-flight
            if (state.inFlight.has(normalizedUrl)) {
                return state.inFlight.get(normalizedUrl);
            }
            
            const link = document.createElement('link');
            link.rel = 'prefetch';
            link.href = normalizedUrl;
            link.as = 'document';
            
            // Priority hints (Chrome 101+)
            if (priority !== 'auto') {
                link.fetchPriority = priority;
            }
            
            const cleanup = () => {
                state.inFlight.delete(normalizedUrl);
            };
            
            link.onload = () => {
                state.prefetched.add(normalizedUrl);
                cleanup();
                log('Prefetch complete (link):', normalizedUrl);
                resolve(normalizedUrl);
            };
            
            link.onerror = () => {
                cleanup();
                warn('Prefetch failed (link):', normalizedUrl);
                reject(new Error(`Prefetch failed: ${normalizedUrl}`));
            };
            
            document.head.appendChild(link);
            
            const promise = new Promise((res, rej) => {
                link.onload = () => { cleanup(); res(normalizedUrl); };
                link.onerror = () => { cleanup(); rej(normalizedUrl); };
            });
            
            state.inFlight.set(normalizedUrl, promise);
        });
    };

    const prefetchWithFetch = (url, priority = 'auto') => {
        return new Promise((resolve, reject) => {
            const normalizedUrl = normalizeUrl(url);
            
            if (state.prefetched.has(normalizedUrl)) {
                return resolve(normalizedUrl);
            }
            
            if (state.inFlight.has(normalizedUrl)) {
                return state.inFlight.get(normalizedUrl);
            }
            
            const options = {
                method: 'GET',
                credentials: 'include',
                cache: 'force-cache',
                mode: 'cors'
            };
            
            // Priority (Chrome 101+)
            if (priority === 'high') {
                options.priority = 'high';
            } else if (priority === 'low') {
                options.priority = 'low';
            }
            
            const promise = fetch(normalizedUrl, options)
                .then(response => {
                    if (response.ok) {
                        state.prefetched.add(normalizedUrl);
                        log('Prefetch complete (fetch):', normalizedUrl);
                        return normalizedUrl;
                    }
                    throw new Error(`HTTP ${response.status}`);
                })
                .catch(error => {
                    warn('Prefetch failed (fetch):', normalizedUrl, error);
                    throw error;
                })
                .finally(() => {
                    state.inFlight.delete(normalizedUrl);
                });
            
            state.inFlight.set(normalizedUrl, promise);
            
            return promise.then(resolve).catch(reject);
        });
    };

    // ═══════════════════════════════════════════════════════════════
    // MAIN PREFETCH/PRERENDER FUNCTIONS
    // ═══════════════════════════════════════════════════════════════
    const prefetch = (url, options = {}) => {
        const {
            priority = 'auto',
            eagerness = 'moderate',
            eager = false,
            context = 'unknown'
        } = options;
        
        const { config } = state;
        const normalizedUrl = normalizeUrl(url);
        
        // Already processed?
        if (state.prefetched.has(normalizedUrl)) {
            log('Already prefetched:', normalizedUrl);
            return Promise.resolve(normalizedUrl);
        }
        
        // Check limits
        if (state.prefetched.size >= config.maxPrefetch) {
            log('Prefetch limit reached');
            return Promise.reject(new Error('Prefetch limit reached'));
        }
        
        // Check if we can prefetch
        if (!canPrefetch(eager)) {
            return Promise.reject(new Error('Prefetch blocked'));
        }
        
        // Callback
        if (config.onPrefetch) {
            config.onPrefetch(normalizedUrl, context);
        }
        
        // Try Speculation Rules first
        if (supportsSpeculationRules()) {
            queueSpeculation(normalizedUrl, 'prefetch', eagerness);
            return Promise.resolve(normalizedUrl);
        }
        
        // Fallback to link prefetch
        if (supportsPrefetch()) {
            return prefetchWithLink(normalizedUrl, priority);
        }
        
        // Last resort: fetch
        return prefetchWithFetch(normalizedUrl, priority);
    };

    const prerender = (url, options = {}) => {
        const {
            eagerness = 'moderate',
            eager = false,
            context = 'unknown'
        } = options;
        
        const { config } = state;
        const normalizedUrl = normalizeUrl(url);
        
        if (!config.enablePrerender) {
            // Fallback to prefetch
            return prefetch(url, { priority: 'high', context });
        }
        
        // Already prerendered?
        if (state.prerendered.has(normalizedUrl)) {
            log('Already prerendered:', normalizedUrl);
            return Promise.resolve(normalizedUrl);
        }
        
        // Check limits
        const limit = (eagerness === 'moderate' || eagerness === 'conservative')
            ? config.maxPrerenderModerate
            : config.maxPrerender;
        
        if (state.prerendered.size >= limit) {
            log('Prerender limit reached, falling back to prefetch');
            return prefetch(url, { priority: 'high', context });
        }
        
        // Check if we can prerender
        if (!canPrerender() && !eager) {
            log('Prerender blocked, falling back to prefetch');
            return prefetch(url, { priority: 'high', context });
        }
        
        // Callback
        if (config.onPrerender) {
            config.onPrerender(normalizedUrl, context);
        }
        
        // Speculation Rules only (prerender requires it)
        if (supportsSpeculationRules()) {
            queueSpeculation(normalizedUrl, 'prerender', eagerness);
            return Promise.resolve(normalizedUrl);
        }
        
        // Fallback to prefetch
        return prefetch(url, { priority: 'high', eagerness, context });
    };

    // ═══════════════════════════════════════════════════════════════
    // REQUEST QUEUE (Rate Limiting)
    // ═══════════════════════════════════════════════════════════════
    const enqueue = (url, type = 'prefetch', options = {}) => {
        state.queue.push({ url, type, options, timestamp: now() });
        processQueue();
    };

    const processQueue = () => {
        if (state.queueProcessing) return;
        if (state.queue.length === 0) return;
        if (!canPrefetch()) return;
        
        const { config } = state;
        const timeSinceLastProcess = now() - state.lastQueueProcess;
        const minInterval = 1000 / config.requestsPerSecond;
        
        if (timeSinceLastProcess < minInterval) {
            setTimeout(processQueue, minInterval - timeSinceLastProcess);
            return;
        }
        
        // Check concurrent limit
        if (state.inFlight.size >= config.maxConcurrent) {
            setTimeout(processQueue, 100);
            return;
        }
        
        state.queueProcessing = true;
        state.lastQueueProcess = now();
        
        const item = state.queue.shift();
        
        if (item) {
            const fn = item.type === 'prerender' ? prerender : prefetch;
            fn(item.url, item.options)
                .catch(() => {})
                .finally(() => {
                    state.queueProcessing = false;
                    if (state.queue.length > 0) {
                        processQueue();
                    }
                });
        } else {
            state.queueProcessing = false;
        }
    };

    // ═══════════════════════════════════════════════════════════════
    // EVENT HANDLERS
    // ═══════════════════════════════════════════════════════════════
    
    // Touch events
    const onTouchStart = (event) => {
        const { config } = state;
        if (!config.enableTouchPrerender) return;
        
        state.lastInteraction = now();
        state.lastInteractionType = 'touch';
        state.touchStartTime = now();
        
        const link = event.target.closest('a');
        if (!isValidLink(link)) return;
        
        const url = getLinkUrl(link);
        if (!url) return;
        
        log('Touch start:', url);
        
        if (config.touchDelay === 0) {
            prerender(url, { eagerness: 'conservative', context: 'touch' });
        } else {
            setTimeout(() => {
                if (state.lastInteractionType === 'touch') {
                    prerender(url, { eagerness: 'conservative', context: 'touch' });
                }
            }, config.touchDelay);
        }
    };

    // Hover events
    const onMouseOver = (event) => {
        const { config } = state;
        if (!config.enableHoverPrefetch) return;
        
        // Skip if recent touch
        if (now() - state.lastInteraction < 1000 && state.lastInteractionType === 'touch') {
            return;
        }
        
        const link = event.target.closest('a');
        if (!isValidLink(link)) return;
        
        const url = getLinkUrl(link);
        if (!url) return;
        
        // Clear previous timeout
        if (state.hoverTimeout) {
            clearTimeout(state.hoverTimeout);
        }
        
        state.hoverTarget = link;
        
        const delay = getAdaptiveDelay();
        
        state.hoverTimeout = setTimeout(() => {
            if (state.hoverTarget === link) {
                log('Hover prefetch:', url);
                
                // If already prefetched, upgrade to prerender
                if (state.prefetched.has(normalizeUrl(url)) && config.enableLayeredUpgrade) {
                    prerender(url, { eagerness: 'moderate', context: 'hover-upgrade' });
                } else {
                    prefetch(url, { priority: 'high', eagerness: 'moderate', context: 'hover' });
                }
            }
        }, delay);
    };

    const onMouseOut = (event) => {
        // Check if moving to child element
        if (event.relatedTarget && 
            event.target.closest('a') === event.relatedTarget.closest('a')) {
            return;
        }
        
        if (state.hoverTimeout) {
            clearTimeout(state.hoverTimeout);
            state.hoverTimeout = null;
        }
        state.hoverTarget = null;
    };

    // Mouse down (pre-click)
    const onMouseDown = (event) => {
        const { config } = state;
        if (!config.enableMousedownPrerender) return;
        
        // Only left click
        if (event.button !== 0 || event.metaKey || event.ctrlKey || event.shiftKey) {
            return;
        }
        
        const link = event.target.closest('a');
        if (!isValidLink(link)) return;
        
        const url = getLinkUrl(link);
        if (!url) return;
        
        state.lastInteraction = now();
        state.lastInteractionType = 'mousedown';
        
        log('Mousedown prerender:', url);
        prerender(url, { eagerness: 'conservative', context: 'mousedown' });
    };

    // Mouse prediction
    const onMouseMove = (event) => {
        const { config } = state;
        if (!config.enableMousePrediction || !config.mousePredictionEnabled) return;
        if (state.pageState !== 'active') return;
        
        const currentTime = now();
        const dt = currentTime - state.lastMousePos.time;
        
        // Update velocity (with smoothing)
        if (dt > 16) { // ~60fps
            const newVx = (event.clientX - state.lastMousePos.x) / dt;
            const newVy = (event.clientY - state.lastMousePos.y) / dt;
            
            // Exponential smoothing
            const alpha = 0.3;
            state.mouseVelocity.x = alpha * newVx + (1 - alpha) * state.mouseVelocity.x;
            state.mouseVelocity.y = alpha * newVy + (1 - alpha) * state.mouseVelocity.y;
            
            state.lastMousePos = { x: event.clientX, y: event.clientY, time: currentTime };
        }
        
        // Throttle prediction
        if (state.predictionFrame) return;
        
        state.predictionFrame = requestAnimationFrame(() => {
            state.predictionFrame = null;
            
            const speed = Math.sqrt(
                state.mouseVelocity.x ** 2 + 
                state.mouseVelocity.y ** 2
            );
            
            if (speed < config.mouseVelocityThreshold) return;
            
            // Predict position
            const predictX = event.clientX + state.mouseVelocity.x * config.mousePredictionDistance;
            const predictY = event.clientY + state.mouseVelocity.y * config.mousePredictionDistance;
            
            const element = document.elementFromPoint(predictX, predictY);
            if (!element) return;
            
            const link = element.closest('a');
            if (!isValidLink(link)) return;
            
            const url = getLinkUrl(link);
            if (!url) return;
            
            const normalizedUrl = normalizeUrl(url);
            if (state.prefetched.has(normalizedUrl)) return;
            
            log('Mouse prediction prefetch:', url);
            prefetch(url, { priority: 'low', eagerness: 'moderate', context: 'prediction' });
        });
    };

    // Keyboard navigation
    const onKeyDown = (event) => {
        // Tab or arrow key navigation
        if (!['Tab', 'ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(event.key)) {
            return;
        }
        
        // Wait for focus to settle
        setTimeout(() => {
            const focused = document.activeElement;
            if (focused && focused.tagName === 'A' && isValidLink(focused)) {
                const url = getLinkUrl(focused);
                if (url) {
                    log('Keyboard focus prefetch:', url);
                    prefetch(url, { priority: 'high', context: 'keyboard' });
                }
            }
        }, 50);
    };

    // ═══════════════════════════════════════════════════════════════
    // VIEWPORT PREFETCHING (Intersection Observer)
    // ═══════════════════════════════════════════════════════════════
    const initViewportPrefetch = () => {
        const { config } = state;
        if (!config.enableViewportPrefetch) return;
        
        state.intersectionObserver = new IntersectionObserver(
            (entries) => {
                for (const entry of entries) {
                    if (!entry.isIntersecting) continue;
                    
                    const link = entry.target;
                    state.intersectionObserver.unobserve(link);
                    
                    if (!isValidLink(link)) continue;
                    
                    const url = getLinkUrl(link);
                    if (!url) continue;
                    
                    // Use requestIdleCallback if available
                    const schedulePrefetch = () => {
                        if (!canPrefetch()) return;
                        log('Viewport prefetch:', url);
                        enqueue(url, 'prefetch', { priority: 'low', eagerness: 'moderate', context: 'viewport' });
                    };
                    
                    if ('requestIdleCallback' in window) {
                        requestIdleCallback(schedulePrefetch, { timeout: 2000 });
                    } else {
                        setTimeout(schedulePrefetch, 200);
                    }
                }
            },
            {
                threshold: config.intersectionThreshold,
                rootMargin: config.intersectionRootMargin
            }
        );
        
        // Observe all links
        observeLinks();
    };

    const observeLinks = () => {
        if (!state.intersectionObserver) return;
        
        const links = document.querySelectorAll('a[href]');
        for (const link of links) {
            if (isValidLink(link) && !state.prefetched.has(normalizeUrl(link.href))) {
                state.intersectionObserver.observe(link);
            }
        }
    };

    // ═══════════════════════════════════════════════════════════════
    // MUTATION OBSERVER (Dynamic Content)
    // ═══════════════════════════════════════════════════════════════
    const initMutationObserver = () => {
        state.mutationObserver = new MutationObserver((mutations) => {
            let hasNewLinks = false;
            
            for (const mutation of mutations) {
                for (const node of mutation.addedNodes) {
                    if (node.nodeType !== Node.ELEMENT_NODE) continue;
                    
                    if (node.tagName === 'A' && isValidLink(node)) {
                        if (state.intersectionObserver) {
                            state.intersectionObserver.observe(node);
                        }
                        hasNewLinks = true;
                    }
                    
                    // Check descendants
                    const links = node.querySelectorAll?.('a[href]');
                    if (links) {
                        for (const link of links) {
                            if (isValidLink(link)) {
                                if (state.intersectionObserver) {
                                    state.intersectionObserver.observe(link);
                                }
                                hasNewLinks = true;
                            }
                        }
                    }
                }
            }
            
            if (hasNewLinks) {
                log('New links detected, observing');
            }
        });
        
        state.mutationObserver.observe(document.body, {
            childList: true,
            subtree: true
        });
    };

    // ═══════════════════════════════════════════════════════════════
    // BFCACHE AWARENESS
    // ═══════════════════════════════════════════════════════════════
    const initBFCache = () => {
        const { config } = state;
        if (!config.enableBFCache) return;
        
        // Page show (includes BFCache restore)
        window.addEventListener('pageshow', (event) => {
            if (event.persisted) {
                state.bfCacheSupported = true;
                state.bfCacheRestored = true;
                
                log('Page restored from BFCache');
                
                // Clear stale state
                state.prefetched.clear();
                state.prerendered.clear();
                clearAllSpeculationRules();
                
                // Re-initialize
                if (config.enableDocumentRules) {
                    createDocumentRules();
                }
                
                // Re-observe links
                requestIdleCallback(() => {
                    observeLinks();
                }, { timeout: 1000 });
            }
        }, { capture: true });
        
        // Page hide (entering BFCache)
        window.addEventListener('pagehide', (event) => {
            if (event.persisted) {
                log('Page entering BFCache');
                cancelPendingOperations();
            }
        }, { capture: true });
    };

    // ═══════════════════════════════════════════════════════════════
    // PAGE LIFECYCLE API
    // ═══════════════════════════════════════════════════════════════
    const initPageLifecycle = () => {
        const { config } = state;
        if (!config.enablePageLifecycle) return;
        
        // Visibility change
        document.addEventListener('visibilitychange', () => {
            if (document.visibilityState === 'hidden') {
                state.wasHidden = true;
                state.pageState = 'hidden';
                log('Page hidden');
                pause();
            } else {
                state.pageState = 'active';
                log('Page visible');
                resume();
                
                if (state.wasHidden) {
                    state.wasHidden = false;
                    requestIdleCallback(() => {
                        observeLinks();
                    }, { timeout: 500 });
                }
            }
        }, { passive: true });
        
        // Freeze/resume (Page Lifecycle API)
        if ('onfreeze' in document) {
            document.addEventListener('freeze', () => {
                state.pageState = 'frozen';
                log('Page frozen');
                cancelPendingOperations();
            }, { passive: true });
            
            document.addEventListener('resume', () => {
                state.pageState = 'active';
                log('Page resumed');
            }, { passive: true });
        }
        
        // Focus/blur
        window.addEventListener('blur', () => {
            if (state.pageState === 'active') {
                state.pageState = 'passive';
            }
        }, { passive: true });
        
        window.addEventListener('focus', () => {
            if (state.pageState === 'passive') {
                state.pageState = 'active';
            }
        }, { passive: true });
    };

    // ═══════════════════════════════════════════════════════════════
    // NAVIGATION TIMING FEEDBACK
    // ═══════════════════════════════════════════════════════════════
    const initNavigationTiming = () => {
        const { config } = state;
        if (!config.adaptiveTimingEnabled) return;
        if (!window.PerformanceObserver) return;
        
        try {
            state.performanceObserver = new PerformanceObserver((list) => {
                for (const entry of list.getEntries()) {
                    if (entry.entryType === 'navigation') {
                        processNavigationTiming(entry);
                    }
                }
            });
            
            state.performanceObserver.observe({ type: 'navigation', buffered: true });
            
            log('Navigation timing initialized');
        } catch (e) {
            warn('Navigation timing not supported');
        }
    };

    const processNavigationTiming = (entry) => {
        const { config } = state;
        
        const timing = {
            loadTime: entry.loadEventEnd - entry.fetchStart,
            ttfb: entry.responseStart - entry.requestStart,
            domProcessing: entry.domContentLoadedEventEnd - entry.responseEnd,
            wasPrefetched: entry.transferSize === 0 && entry.decodedBodySize > 0,
            timestamp: Date.now()
        };
        
        // Track hit/miss
        if (timing.wasPrefetched) {
            state.prefetchHits++;
        } else {
            state.prefetchMisses++;
        }
        
        // Store timing
        state.navigationTimings.push(timing);
        if (state.navigationTimings.length > config.timingHistorySize) {
            state.navigationTimings.shift();
        }
        
        // Update adaptive delay
        updateAdaptiveDelay();
        
        log('Navigation timing:', timing);
    };

    const updateAdaptiveDelay = () => {
        const { config } = state;
        
        if (state.navigationTimings.length < 3) return;
        
        const recent = state.navigationTimings.slice(-5);
        const avgLoadTime = recent.reduce((sum, t) => sum + t.loadTime, 0) / recent.length;
        const prefetchedCount = recent.filter(t => t.wasPrefetched).length;
        const hitRate = prefetchedCount / recent.length;
        
        let delay = config.hoverDelay;
        
        // Slow loads = more aggressive (lower delay)
        if (avgLoadTime > 2000) {
            delay = Math.max(config.minHoverDelay, delay * 0.5);
        } else if (avgLoadTime < 500) {
            delay = Math.min(config.maxHoverDelay, delay * 1.3);
        }
        
        // High hit rate = more aggressive
        if (hitRate > 0.7) {
            delay = Math.max(config.minHoverDelay, delay * 0.8);
        } else if (hitRate < 0.2 && prefetchedCount > 0) {
            delay = Math.min(config.maxHoverDelay, delay * 1.2);
        }
        
        state.adaptiveDelay = Math.round(delay);
        
        log('Adaptive delay updated:', state.adaptiveDelay, 'ms (hit rate:', Math.round(hitRate * 100) + '%)');
    };

    const getAdaptiveDelay = () => {
        const { config } = state;
        return config.adaptiveTimingEnabled ? state.adaptiveDelay : config.hoverDelay;
    };

    // ═══════════════════════════════════════════════════════════════
    // SERVICE WORKER INTEGRATION (Optional)
    // ═══════════════════════════════════════════════════════════════
    const initServiceWorker = async () => {
        const { config } = state;
        if (!config.enableServiceWorker) return;
        if (!('serviceWorker' in navigator)) return;
        
        try {
            const registration = await navigator.serviceWorker.ready;
            state.swRegistration = registration;
            
            log('Service Worker ready');
            
            // Listen for messages from SW
            navigator.serviceWorker.addEventListener('message', (event) => {
                if (event.data.type === 'PREFETCH_COMPLETE') {
                    state.prefetched.add(event.data.url);
                    log('SW prefetch complete:', event.data.url);
                }
            });
        } catch (e) {
            warn('Service Worker not available');
        }
    };

    const prefetchViaServiceWorker = (url) => {
        if (!state.swRegistration || !state.swRegistration.active) {
            return false;
        }
        
        state.swRegistration.active.postMessage({
            type: 'PREFETCH',
            url: normalizeUrl(url)
        });
        
        return true;
    };

    // ═══════════════════════════════════════════════════════════════
    // CONTROL FUNCTIONS
    // ═══════════════════════════════════════════════════════════════
    const pause = () => {
        state.isPaused = true;
        
        if (state.speculationTimer) {
            clearTimeout(state.speculationTimer);
            state.speculationTimer = null;
        }
        
        if (state.hoverTimeout) {
            clearTimeout(state.hoverTimeout);
            state.hoverTimeout = null;
        }
        
        log('Paused');
    };

    const resume = () => {
        state.isPaused = false;
        
        // Flush pending speculation
        if (state.speculationBatch.prefetch.size > 0 || 
            state.speculationBatch.prerender.size > 0) {
            scheduleSpeculationFlush();
        }
        
        // Process queue
        processQueue();
        
        log('Resumed');
    };

    const cancelPendingOperations = () => {
        // Clear timers
        if (state.speculationTimer) {
            clearTimeout(state.speculationTimer);
            state.speculationTimer = null;
        }
        
        if (state.hoverTimeout) {
            clearTimeout(state.hoverTimeout);
            state.hoverTimeout = null;
        }
        
        // Clear batches
        state.speculationBatch.prefetch.clear();
        state.speculationBatch.prerender.clear();
        
        // Clear queue
        state.queue = [];
    };

    const reset = () => {
        // Cancel pending
        cancelPendingOperations();
        
        // Clear state
        state.prefetched.clear();
        state.prerendered.clear();
        state.inFlight.clear();
        state.navigationTimings = [];
        state.prefetchHits = 0;
        state.prefetchMisses = 0;
        state.adaptiveDelay = state.config.hoverDelay;
        
        // Clear speculation rules
        clearAllSpeculationRules();
        
        // Re-observe links
        observeLinks();
        
        // Recreate document rules
        if (state.config.enableDocumentRules) {
            createDocumentRules();
        }
        
        log('Reset complete');
    };

    // ═══════════════════════════════════════════════════════════════
    // CONNECTION CHANGE HANDLER
    // ═══════════════════════════════════════════════════════════════
    const initConnectionHandler = () => {
        const connection = navigator.connection || 
                          navigator.mozConnection || 
                          navigator.webkitConnection;
        
        if (connection) {
            connection.addEventListener('change', () => {
                const conn = getConnection();
                log('Connection changed:', conn);
                
                // Re-evaluate pending operations
                if (!canPrefetch()) {
                    cancelPendingOperations();
                }
                
                updateAdaptiveDelay();
            });
        }
    };

    // ═══════════════════════════════════════════════════════════════
    // INITIALIZATION
    // ═══════════════════════════════════════════════════════════════
    const init = (userConfig = {}) => {
        // Prevent double init
        if (state.initialized) {
            warn('Already initialized');
            return;
        }
        
        // Merge config
        state.config = { ...defaultConfig, ...userConfig };
        state.adaptiveDelay = state.config.hoverDelay;
        
        const { config } = state;
        
        // Check browser support
        if (!supportsPrefetch()) {
            warn('Prefetch not supported in this browser');
            return;
        }
        
        log('Initializing...');
        log('Features:', detectFeatures());
        log('Connection:', getConnection());
        
        // Initialize systems
        initBFCache();
        initPageLifecycle();
        initNavigationTiming();
        initConnectionHandler();
        
        // Service Worker (async)
        initServiceWorker();
        
        // Event listeners
        const passiveCapture = { capture: true, passive: true };
        
        document.addEventListener('touchstart', onTouchStart, passiveCapture);
        document.addEventListener('mouseover', onMouseOver, passiveCapture);
        document.addEventListener('mouseout', onMouseOut, passiveCapture);
        document.addEventListener('mousedown', onMouseDown, passiveCapture);
        document.addEventListener('keydown', onKeyDown, passiveCapture);
        
        if (config.enableMousePrediction) {
            document.addEventListener('mousemove', throttle(onMouseMove, 16), passiveCapture);
        }
        
        // Document rules (if supported and enabled)
        if (config.enableDocumentRules && supportsSpeculationRules()) {
            createDocumentRules();
        }
        
        // Viewport prefetch
        initViewportPrefetch();
        
        // Mutation observer
        initMutationObserver();
        
        state.initialized = true;
        
        log('Ready!');
    };

    // Auto-init when DOM ready
    const autoInit = () => {
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', () => init());
        } else {
            init();
        }
    };

    // Check for data attributes on script tag
    const checkScriptConfig = () => {
        const script = document.currentScript;
        if (!script) return {};
        
        const config = {};
        
        if ('debug' in script.dataset) config.debug = true;
        if ('noViewport' in script.dataset) config.enableViewportPrefetch = false;
        if ('noHover' in script.dataset) config.enableHoverPrefetch = false;
        if ('noTouch' in script.dataset) config.enableTouchPrerender = false;
        if ('noMousedown' in script.dataset) config.enableMousedownPrerender = false;
        if ('noPrediction' in script.dataset) config.enableMousePrediction = false;
        if ('noPrerender' in script.dataset) config.enablePrerender = false;
        if ('crossOrigin' in script.dataset) config.enableCrossOrigin = true;
        if ('serviceWorker' in script.dataset) config.enableServiceWorker = true;
        if (script.dataset.delay) config.hoverDelay = parseInt(script.dataset.delay, 10);
        if (script.dataset.limit) config.maxPrefetch = parseInt(script.dataset.limit, 10);
        
        return config;
    };

    // ═══════════════════════════════════════════════════════════════
    // PUBLIC API
    // ═══════════════════════════════════════════════════════════════
    const api = {
        // Lifecycle
        init,
        pause,
        resume,
        reset,
        
        // Core functions
        prefetch,
        prerender,
        
        // Queue
        enqueue,
        flush: flushSpeculationBatch,
        
        // State
        getState: () => ({
            initialized: state.initialized,
            isPaused: state.isPaused,
            pageState: state.pageState,
            prefetchedCount: state.prefetched.size,
            prerenderedCount: state.prerendered.size,
            queueLength: state.queue.length,
            inFlightCount: state.inFlight.size,
            adaptiveDelay: state.adaptiveDelay,
            hitRate: state.prefetchHits + state.prefetchMisses > 0
                ? state.prefetchHits / (state.prefetchHits + state.prefetchMisses)
                : 0,
            bfCacheSupported: state.bfCacheSupported,
            features: { ...state.features }
        }),
        
        // Stats
        getStats: () => ({
            prefetchHits: state.prefetchHits,
            prefetchMisses: state.prefetchMisses,
            hitRate: state.prefetchHits + state.prefetchMisses > 0
                ? state.prefetchHits / (state.prefetchHits + state.prefetchMisses)
                : 0,
            avgLoadTime: state.navigationTimings.length > 0
                ? state.navigationTimings.reduce((s, t) => s + t.loadTime, 0) / state.navigationTimings.length
                : null,
            navigationCount: state.navigationTimings.length,
            adaptiveDelay: state.adaptiveDelay,
            connection: getConnection()
        }),
        
        // Lists
        getPrefetched: () => [...state.prefetched],
        getPrerendered: () => [...state.prerendered],
        
        // Config
        configure: (newConfig) => {
            Object.assign(state.config, newConfig);
            log('Config updated:', newConfig);
        },
        
        // Feature detection
        supports: {
            speculationRules: supportsSpeculationRules,
            prefetch: supportsPrefetch,
            all: detectFeatures
        },
        
        // Version
        version: '1.0.0'
    };

    // Auto-initialize with script config
    const scriptConfig = checkScriptConfig();
    if (Object.keys(scriptConfig).length > 0) {
        Object.assign(state.config, scriptConfig);
    }
    
    // Auto-init unless data-manual attribute is present
    const currentScript = document.currentScript;
    if (!currentScript || !('manual' in currentScript.dataset)) {
        autoInit();
    }

    return api;
});
